from __future__ import annotations
from dataclasses import dataclass
from typing import Optional
from domain_decision import DomainStewardDecision

class PermittedApplicationGate:
    """Checks whether a document may be served to a specific application."""

    def __init__(self, decision_store: dict[str, DomainStewardDecision]):
        # decision_store: doc_id -> DomainStewardDecision
        self.decisions = decision_store

    def is_permitted(self, doc_id: str, application_id: str) -> tuple[bool, str]:
        """Return (permitted, reason). Call before every retrieval result is served."""
        decision = self.decisions.get(doc_id)
        if decision is None:
            return False, f"No steward decision found for doc {doc_id}; deny by default"
        if decision.is_overdue_for_review():
            return False, (
                f"Document {doc_id} is overdue for steward review "
                f"(review_by={decision.review_by_utc}); serve after re-confirmation"
            )
        if not decision.permits_application(application_id):
            return False, (
                f"Document {doc_id} is not in the permitted_application_ids list "
                f"for application {application_id}"
            )
        return True, "permitted"


class PermittedApplicationFilteredRetriever:
    """Wraps any retriever to enforce per-document application policy."""

    def __init__(self, base_retriever, gate: PermittedApplicationGate, application_id: str):
        self.retriever      = base_retriever
        self.gate           = gate
        self.application_id = application_id

    def retrieve(self, query_embedding, collection, top_k, user_label, lineage_id):
        candidates = self.retriever.retrieve(
            query_embedding, collection, top_k * 3, user_label, lineage_id
        )
        served, blocked = [], []
        for chunk in candidates:
            permitted, reason = self.gate.is_permitted(chunk.doc_id, self.application_id)
            if permitted:
                served.append(chunk)
            else:
                blocked.append((chunk.chunk_id, reason))
            if len(served) == top_k:
                break
        # Log blocked chunks for audit (omitted for brevity)
        return served
